import torch
import torch.nn as nn
import torch.nn.functional as F
import torch.distributed as dist


def _world_size():
    return dist.get_world_size() if dist.is_available() and dist.is_initialized() else 1


def _rank():
    return dist.get_rank() if dist.is_available() and dist.is_initialized() else 0


class _GatherLastDim(torch.autograd.Function):
    @staticmethod
    def forward(ctx, x):
        ws = _world_size()
        if ws == 1:
            return x
        xc = x.contiguous()
        tensors = [torch.empty_like(xc) for _ in range(ws)]
        dist.all_gather(tensors, xc)
        return torch.cat(tensors, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        ws = _world_size()
        if ws == 1:
            return grad_output
        chunk = grad_output.chunk(ws, dim=-1)[_rank()]
        return chunk.contiguous()


class _AllReduce(torch.autograd.Function):
    @staticmethod
    def forward(ctx, x):
        ws = _world_size()
        if ws == 1:
            return x
        xc = x.clone()
        dist.all_reduce(xc)
        return xc

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


class ColumnParallelLinear(torch.nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features
        ws = _world_size()
        rank = _rank()
        self.out_per_rank = out_features // ws
        # master_weight: [out_features, in_features]; split along output dim (dim 0)
        w = master_weight.detach().chunk(ws, dim=0)[rank].clone()
        self.weight = nn.Parameter(w.contiguous())
        if bias:
            self.bias = nn.Parameter(torch.zeros(self.out_per_rank,
                                                  dtype=self.weight.dtype,
                                                  device=self.weight.device))
        else:
            self.register_parameter("bias", None)

    def forward(self, x):
        local = F.linear(x, self.weight, self.bias)
        return _GatherLastDim.apply(local)


class RowParallelLinear(torch.nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features
        ws = _world_size()
        rank = _rank()
        self.in_per_rank = in_features // ws
        # master_weight: [out_features, in_features]; split along input dim (dim 1)
        w = master_weight.detach().chunk(ws, dim=1)[rank].clone()
        self.weight = nn.Parameter(w.contiguous())
        if bias:
            self.bias = nn.Parameter(torch.zeros(out_features,
                                                 dtype=self.weight.dtype,
                                                 device=self.weight.device))
        else:
            self.register_parameter("bias", None)

    def forward(self, x):
        local = F.linear(x, self.weight)
        out = _AllReduce.apply(local)
        if self.bias is not None:
            out = out + self.bias
        return out
